INSERT INTO jobs (job_name, industry, city, company_type, salary_min, salary_max, skills, soft_skills, is_fresh_friendly, friendly_level, jd_content, core_duties, education, major, experience, post_type, bonus_skills, salary_range, post_time, apply_deadline, jd_link, post_category, party_label) VALUES ('招聘高级专员 - 上海（校招）', '化工 / 能源 / 环保', '上海', '上市公司', 14000, 17000, '1. 熟练掌握招聘全流程操作规范，可独立完成中高端岗位招聘全流程；2. 具备多渠道招聘拓展与维护能力，可根据岗位需求匹配对应招聘渠道；3. 具备招聘数据统计与分析能力，可独立完成数据报表输出，支撑招聘策略调整；4. 具备优秀的英语听说读写能力，可熟练进行英文面试和全英文沟通；5. 熟练使用办公软件与招聘管理系统，可高效完成简历筛选、面试跟进等基础工作。', '1. 具备优秀的沟通协调能力、团队协作精神，可高效对接业务端与候选人；2. 结果导向，目标感强，可独立完成招聘交付目标；3. 具备较强的流程优化意识，可主动发现并改善招聘流程中的问题；4. 学习能力强，可快速适配新能源行业的招聘需求与岗位特点；5. 工作严谨细致，有较强的责任心和抗压能力。', 1, '友好', '1. 负责公司高级人才的招聘工作，包括职位发布、简历筛选、面试安排及跟进等全流程；2. 拓展并维护招聘渠道，确保招聘渠道的多样性和有效性；3. 参与招聘流程优化，提升招聘效率和候选人体验；4. 协助完成招聘数据统计与分析，为招聘策略调整提供依据。', '招聘全流程执行, 渠道拓展与运营, 简历筛选与面试, 招聘数据分析, 招聘流程优化', '本科及以上', '人力资源、心理学等相关专业优先', '具备 1 年以上招聘工作经验优先，优秀毕业 1 年内应届生可放宽，熟悉招聘流程和方法', '应届生校招', '人力资源管理师相关证书优先、有新能源行业招聘经验优先、有校园招聘项目运营经验优先', '14k-17k / 月', '46106', '46107', 'https://www.shixiseng.com/intern/inn_pbxxrp3b6q8w?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('招聘助理 - 苏州（校招）', '互联网 / IT', '苏州', '民营企业', 5000, 10000, '1. 熟练使用 Word 等办公软件，可独立完成简历筛选、面试跟进等基础工作；2. 掌握主流招聘渠道的使用方法，可独立完成候选人初步搜寻与筛选；3. 具备基础的职位需求分析能力，可精准识别岗位与候选人的匹配度；4. 具备基础的市场调研与信息整理能力，可完成行业人才信息收集。', '1. 对人力资源招聘工作有浓厚兴趣，具备良好的沟通能力和团队协作精神；2. 有较强的学习能力和责任心，能够承受一定的工作压力；3. 性格积极主动，有主观能动性和问题解决意识，具备目标导向的特质；4. 亲和力强，有良好的服务意识，可高效完成候选人沟通对接。', 1, '极度友好', '1. 协助资深招聘进行职位分析，明确招聘需求；2. 利用各种渠道搜索候选人简历，进行初步筛选；3. 与候选人进行沟通，了解其意向和基本情况；4. 协助安排面试，跟进面试流程；5. 参与市场调研，了解行业动态和人才趋势。', '招聘全流程执行, 简历筛选与面试, 渠道拓展与运营, 候选人寻访 /mapping', '本科及以上', '人力资源、心理学等相关专业优先', '无强制经验要求，优秀应届生可投，有人力资源相关实习经验优先', '应届生校招', '人力资源管理师相关证书优先、有校园招聘项目运营经验优先、熟练使用 AI 工具优先', '5k-10k / 月', '46105', '46198', 'https://www.shixiseng.com/intern/inn_iu7gqvtjf9je?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('校园招聘专员 - 上海（校招', '人力资源服务 / 咨询', '上海', '上市公司', 5000, 10000, '1. 熟练掌握校园招聘全流程操作规范，可独立完成校招项目的落地执行；2. 具备高校渠道开发与维护能力，可搭建稳定的校园招聘合作网络；3. 可独立完成宣讲会、双选会等校招活动的统筹规划与落地执行；4. 具备校招数据统计与分析能力，可独立完成基础分析报告，支撑招聘策略优化；5. 熟练使用 Office 办公软件，可高效完成简历筛选、面试协调、人才库维护等基础工作。', '1. 具备优秀的语言与书面沟通能力，可高效对接高校、候选人及内部团队；2. 具备极强的组织协调能力与执行力，可独立推进多线程项目落地；3. 性格开朗外向，积极主动，对招聘工作充满热情，具备极强的学习能力、抗压能力与团队协作精神；4. 工作严谨细致，责任心强，注重细节，可适应出差及招聘旺季的工作节奏。', 1, '友好', '1. 参与制定校园招聘计划，负责目标区域的目标高校筛选与招聘行程规划，统筹校园宣讲会、双选会等招聘活动的落地执行；2. 开发并维护目标高校就业指导中心、院系等合作渠道，搭建稳定的校园招聘网络；3. 负责校园招聘全流程推进，包括岗位发布、简历收集与初筛、测评、面试组织协调，以及 offer 发放、入职前跟踪答疑等全流程工作；4. 统计整理校园招聘相关数据，形成基础分析报告，为优化招聘策略、提升招聘效率提供支持；协助建立和维护校园人才库。', '校招项目运营, 招聘全流程执行, 渠道拓展与运营, 简历筛选与面试, 招聘数据分析', '本科及以上', '人力资源管理、工商管理等相关专业优先，专业不限', '有校园招聘、社团活动策划或招聘实习经验者优先，优秀应届生可投', '应届生校招', '人力资源管理师相关证书优先、有校园招聘项目运营经验优先、有社团活动策划经验优先、熟练使用主流招聘平台者优先', '薪资面议', '46104', '46203', 'https://www.shixiseng.com/intern/inn_mh9ccdlikfrn?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '乙方（人力资源服务商 / 猎头 / 咨询公司）'), ('招聘助理 - 广州（校招）', '互联网 / IT', '广州', '民营企业', 4000, 5000, '1. 熟练操作猎聘、BOSS 直聘、LinkedIn 等主流招聘渠道，掌握候选人主动寻访方法；2. 掌握简历筛选与初步评估技能，可精准识别候选人与岗位的匹配度；3. 具备优秀的电话沟通与初面评估能力，可独立完成候选人初步沟通；4. 可熟练使用办公软件，完成招聘数据统计、候选人报告撰写等基础工作；5. 掌握 ATS/CRM 人才库系统的基础操作，可完成候选人信息录入与维护。', '1. 外向开朗，乐于沟通，具备良好的倾听和表达能力，可快速与陌生人建立信任；2. 学习能力强，可快速理解不同行业、不同岗位的招聘需求，抓住岗位核心卖点；3. 抗压能力强，可适应快节奏、多任务的工作环境，面对拒绝可快速调整心态；4. 结果导向，有明确的自我驱动力，可主动推进招聘流程到下一阶段。', 1, '极度友好', '1. 职位分析与渠道拓展：对接业务端需求，深入理解招聘职位要求，选择合适渠道发布职位，主动寻访潜在候选人；2. 人才寻访与初步沟通：对收到的简历进行初步筛选，主动寻访候选人，完成电话初访沟通，评估候选人匹配度；3. 面试协调与流程推进：整理候选人信息，撰写推荐报告，协调安排面试，跟进面试全流程，完成候选人入职跟进与回访；4. 数据与系统维护：将候选人信息准确录入人才库系统，协助团队统计招聘数据，为流程优化提供支持。', '招聘全流程执行, 渠道拓展与运营, 简历筛选与面试, 候选人寻访 /mapping, 招聘数据分析', '大专及以上', '专业不限，人力资源管理、心理学、市场营销等相关专业优先', '接受优秀应届毕业生，有电话销售、客服、招聘、实习或人力资源相关经验优先', '应届生校招', '人力资源管理师相关证书优先、有校园招聘项目运营经验优先、有销售 / 客服相关经验优先', '4k-5k / 月', '46097', NULL, 'https://www.shixiseng.com/intern/inn_vv7we8xy5vo5?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）'), ('HR 招聘专员 - 武汉（校招）', '互联网 / IT', '武汉', '民营企业', 8000, 12000, '1. 熟练掌握互联网 / 游戏招聘全流程，可独立完成技术、产品、市场、运营、游戏等岗位的招聘工作；2. 具备多渠道招聘拓展与维护能力，可根据岗位需求匹配对应招聘渠道；3. 掌握候选人 mapping 寻访技能，可独立完成定向人才挖掘与评估；4. 具备优秀的项目执行能力和推进能力，可独立完成招聘全流程闭环。', '1. 具备优秀的沟通能力和推进能力，可高效对接业务端与候选人；2. 具备优秀的沟通能力和问题解决能力，具备服务意识；3. 自我驱动力强，目标感强，可主动完成招聘交付目标；4. 学习能力强，可快速理解游戏行业的岗位需求与行业特点。', 1, '友好', '1. 理解业务招聘需求，跟进、拓展招聘渠道，优化招聘流程，进行招聘渠道的拓展；2. 执行人才搜索和寻访计划，甄选、评估候选人匹配度；3. 与业务部门保持有效沟通，跟进招聘结果和流程反馈；4. 收集市场人才信息，包括竞争对手信息，定向人才挖掘。', '招聘全流程执行, 渠道拓展与运营, 候选人寻访 /mapping, 简历筛选与面试, 招聘流程优化', '本科及以上', '专业不限', '无强制经验要求，优秀应届生可投，有互联网 / 游戏招聘经验优先', '应届生校招', '人力资源管理师相关证书优先、有游戏行业招聘经验优先、有校园招聘项目运营经验优先', '8k-12k / 月', '45985', '46236', 'https://www.shixiseng.com/intern/inn_468cuykjbp9p?pcm=pc_SearchList', '招聘类 (含招聘专员 / 助理 / 校招专员)', '甲方（企业自有 HR 岗）');